class CreditCardInfo {
  final String cardNumber;
  final String expiryMonth;
  final String expiryYear;
  final String cvv;
  final String cardHolderName;
  final String? billingAddress;
  final String? zipCode;

  CreditCardInfo({
    required this.cardNumber,
    required this.expiryMonth,
    required this.expiryYear,
    required this.cvv,
    required this.cardHolderName,
    this.billingAddress,
    this.zipCode,
  });

  bool validate() {
    if (!_validateCardNumber(cardNumber)) return false;
    if (!_validateExpiry(expiryMonth, expiryYear)) return false;
    if (!_validateCVV(cvv)) return false;
    return true;
  }

  bool _validateCardNumber(String number) {
    final cleaned = number.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;

    int sum = 0;
    bool alternate = false;
    for (int i = cleaned.length - 1; i >= 0; i--) {
      int digit = int.parse(cleaned[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  bool _validateExpiry(String month, String year) {
    final m = int.tryParse(month);
    final y = int.tryParse(year);
    if (m == null || y == null) return false;
    if (m < 1 || m > 12) return false;

    final now = DateTime.now();
    final fullYear = y < 100 ? 2000 + y : y;
    final expiryDate = DateTime(fullYear, m + 1, 0);
    return expiryDate.isAfter(now);
  }

  bool _validateCVV(String cvv) {
    return cvv.length >= 3 && cvv.length <= 4 && int.tryParse(cvv) != null;
  }

  String get maskedCardNumber {
    final cleaned = cardNumber.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 4) return '****';
    return '**** **** **** ${cleaned.substring(cleaned.length - 4)}';
  }
}

