abstract class PaymentGateway {
  Future<PaymentResult> processPayment(PaymentTransaction transaction);
  Future<PaymentResult> refundPayment(String transactionId, double amount);
  Future<bool> verifyPayment(String transactionId);
}

class StripeGateway implements PaymentGateway {
  final PaymentConfig config;
  final http.Client _client;

  StripeGateway(this.config) : _client = http.Client();

  @override
  Future<PaymentResult> processPayment(PaymentTransaction transaction) async {
    try {
      final url = Uri.parse('https://api.stripe.com/v1/payment_intents');
      final response = await _client.post(
        url,
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'amount': (transaction.amount * 100).toInt().toString(),
          'currency': transaction.currency.toLowerCase(),
          'metadata[transaction_id]': transaction.id,
          'metadata[user_id]': transaction.userId,
        },
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return PaymentResult(
          success: true,
          transaction: transaction.copyWith(
            status: PaymentStatus.completed,
            receiptData: data['id'],
          ),
          additionalData: data,
        );
      } else {
        return PaymentResult(
          success: false,
          transaction: transaction.copyWith(status: PaymentStatus.failed),
          errorMessage: 'Stripe payment failed: ${response.body}',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        transaction: transaction.copyWith(status: PaymentStatus.failed),
        errorMessage: 'Stripe error: $e',
      );
    }
  }

  @override
  Future<PaymentResult> refundPayment(String transactionId, double amount) async {
    try {
      final url = Uri.parse('https://api.stripe.com/v1/refunds');
      final response = await _client.post(
        url,
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'payment_intent': transactionId,
          'amount': (amount * 100).toInt().toString(),
        },
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return PaymentResult(
          success: true,
          additionalData: data,
        );
      } else {
        return PaymentResult(
          success: false,
          errorMessage: 'Refund failed: ${response.body}',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Refund error: $e',
      );
    }
  }

  @override
  Future<bool> verifyPayment(String transactionId) async {
    try {
      final url = Uri.parse('https://api.stripe.com/v1/payment_intents/$transactionId');
      final response = await _client.get(
        url,
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
        },
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return data['status'] == 'succeeded';
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  Future<String> createPaymentToken(CreditCardInfo cardInfo) async {
    try {
      final url = Uri.parse('https://api.stripe.com/v1/tokens');
      final response = await _client.post(
        url,
        headers: {
          'Authorization': 'Bearer ${config.stripePublishableKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'card[number]': cardInfo.cardNumber.replaceAll(' ', ''),
          'card[exp_month]': cardInfo.expiryMonth,
          'card[exp_year]': cardInfo.expiryYear,
          'card[cvc]': cardInfo.cvv,
          'card[name]': cardInfo.cardHolderName,
        },
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return data['id'];
      } else {
        throw Exception('Failed to create token: ${response.body}');
      }
    } catch (e) {
      throw Exception('Token creation error: $e');
    }
  }
}

